import{_ as e,o as d,c as i,ak as r}from"./chunks/framework.CRp2eYiK.js";const c=JSON.parse('{"title":"高阶数据分析","description":"","frontmatter":{},"headers":[],"relativePath":"help/sakura/advanced.md","filePath":"doc/help/sakura/advanced.md"}'),o={name:"help/sakura/advanced.md"};function p(n,a,t,s,l,x){return d(),i("div",null,[...a[0]||(a[0]=[r('<h1 id="高阶数据分析" tabindex="-1">高阶数据分析 <a class="header-anchor" href="#高阶数据分析" aria-label="Permalink to “高阶数据分析”">​</a></h1><div class="warning custom-block github-alert"><p class="custom-block-title">数据要求</p><p>以下功能<strong>必须上传游戏数据</strong>才能使用。请先完成 <a href="./user-data#数据上传">数据上传</a>。</p></div><h2 id="排位与评分" tabindex="-1">排位与评分 <a class="header-anchor" href="#排位与评分" aria-label="Permalink to “排位与评分”">​</a></h2><h3 id="查看排位信息" tabindex="-1">查看排位信息 <a class="header-anchor" href="#查看排位信息" aria-label="Permalink to “查看排位信息”">​</a></h3><div style="background:#f5f7fa;border-radius:12px;padding:16px;margin:12px 0;border-left:4px solid #4a90e2;"><div style="display:flex;align-items:center;margin-bottom:8px;"><span style="background:#4a90e2;color:white;padding:4px 12px;border-radius:12px;font-size:12px;font-weight:bold;">指令</span></div><div style="background:white;padding:12px 16px;border-radius:8px;font-family:monospace;color:#333;"> rk </div></div><p>获取玩家当前排位信息。</p><h3 id="b39-分析" tabindex="-1">B39 分析 <a class="header-anchor" href="#b39-分析" aria-label="Permalink to “B39 分析”">​</a></h3><div style="background:#f5f7fa;border-radius:12px;padding:16px;margin:12px 0;border-left:4px solid #4a90e2;"><div style="display:flex;align-items:center;margin-bottom:8px;"><span style="background:#4a90e2;color:white;padding:4px 12px;border-radius:12px;font-size:12px;font-weight:bold;">指令</span></div><div style="background:white;padding:12px 16px;border-radius:8px;font-family:monospace;color:#333;"> b39 </div></div><p>获取 Rating 最高的 39 首歌曲及总分（参考用）。</p><h3 id="b30-分析" tabindex="-1">B30 分析 <a class="header-anchor" href="#b30-分析" aria-label="Permalink to “B30 分析”">​</a></h3><div style="background:#f5f7fa;border-radius:12px;padding:16px;margin:12px 0;border-left:4px solid #4a90e2;"><div style="display:flex;align-items:center;margin-bottom:8px;"><span style="background:#4a90e2;color:white;padding:4px 12px;border-radius:12px;font-size:12px;font-weight:bold;">指令</span></div><div style="background:white;padding:12px 16px;border-radius:8px;font-family:monospace;color:#333;"> pjsk b30 </div></div><p>获取 Rating 最高的 30 首歌曲及平均分（算法不同）。</p><h2 id="歌曲进度查询" tabindex="-1">歌曲进度查询 <a class="header-anchor" href="#歌曲进度查询" aria-label="Permalink to “歌曲进度查询”">​</a></h2><h3 id="expert-进度" tabindex="-1">Expert 进度 <a class="header-anchor" href="#expert-进度" aria-label="Permalink to “Expert 进度”">​</a></h3><div style="background:#f5f7fa;border-radius:12px;padding:16px;margin:12px 0;border-left:4px solid #4a90e2;"><div style="display:flex;align-items:center;margin-bottom:8px;"><span style="background:#4a90e2;color:white;padding:4px 12px;border-radius:12px;font-size:12px;font-weight:bold;">指令</span></div><div style="background:white;padding:12px 16px;border-radius:8px;font-family:monospace;color:#333;"> pjsk进度ex </div></div><p>查询 <strong>Expert</strong> 难度歌曲完成情况（AP/FC/Clear）。</p><h3 id="append-进度" tabindex="-1">Append 进度 <a class="header-anchor" href="#append-进度" aria-label="Permalink to “Append 进度”">​</a></h3><div style="background:#f5f7fa;border-radius:12px;padding:16px;margin:12px 0;border-left:4px solid #4a90e2;"><div style="display:flex;align-items:center;margin-bottom:8px;"><span style="background:#4a90e2;color:white;padding:4px 12px;border-radius:12px;font-size:12px;font-weight:bold;">指令</span></div><div style="background:white;padding:12px 16px;border-radius:8px;font-family:monospace;color:#333;"> pjsk进度apd </div></div><p>查询 <strong>Append</strong> 难度歌曲完成情况。</p><h2 id="详细信息查询" tabindex="-1">详细信息查询 <a class="header-anchor" href="#详细信息查询" aria-label="Permalink to “详细信息查询”">​</a></h2><h3 id="个人详细信息" tabindex="-1">个人详细信息 <a class="header-anchor" href="#个人详细信息" aria-label="Permalink to “个人详细信息”">​</a></h3><div style="background:#f5f7fa;border-radius:12px;padding:16px;margin:12px 0;border-left:4px solid #4a90e2;"><div style="display:flex;align-items:center;margin-bottom:8px;"><span style="background:#4a90e2;color:white;padding:4px 12px;border-radius:12px;font-size:12px;font-weight:bold;">指令</span></div><div style="background:white;padding:12px 16px;border-radius:8px;font-family:monospace;color:#333;"> pjskdetail </div></div><p>获取详细信息，包括金币、水晶、家具、每日挑战等。</p><blockquote><p>介意隐私者可私聊查询。</p></blockquote><h3 id="卡牌图鉴" tabindex="-1">卡牌图鉴 <a class="header-anchor" href="#卡牌图鉴" aria-label="Permalink to “卡牌图鉴”">​</a></h3><div style="background:#f5f7fa;border-radius:12px;padding:16px;margin:12px 0;border-left:4px solid #4a90e2;"><div style="display:flex;align-items:center;margin-bottom:8px;"><span style="background:#4a90e2;color:white;padding:4px 12px;border-radius:12px;font-size:12px;font-weight:bold;">指令</span></div><div style="background:white;padding:12px 16px;border-radius:8px;font-family:monospace;color:#333;"> pjskcard </div></div><p>获取个人卡牌图鉴。</p><div style="background:#f5f7fa;border-radius:12px;padding:16px;margin:12px 0;border-left:4px solid #4a90e2;"><div style="display:flex;align-items:center;margin-bottom:8px;"><span style="background:#4a90e2;color:white;padding:4px 12px;border-radius:12px;font-size:12px;font-weight:bold;">指令</span></div><div style="background:white;padding:12px 16px;border-radius:8px;font-family:monospace;color:#333;"> pjskcard+角色名 </div></div><p>查指定角色的卡牌（如：pjskcard+奏）。</p><h3 id="活动历史" tabindex="-1">活动历史 <a class="header-anchor" href="#活动历史" aria-label="Permalink to “活动历史”">​</a></h3><div style="background:#f5f7fa;border-radius:12px;padding:16px;margin:12px 0;border-left:4px solid #4a90e2;"><div style="display:flex;align-items:center;margin-bottom:8px;"><span style="background:#4a90e2;color:white;padding:4px 12px;border-radius:12px;font-size:12px;font-weight:bold;">指令</span></div><div style="background:white;padding:12px 16px;border-radius:8px;font-family:monospace;color:#333;"> pjskevent </div></div><p>获取个人历史最高活动排名记录（近 10 次）。</p><h2 id="多服支持" tabindex="-1">多服支持 <a class="header-anchor" href="#多服支持" aria-label="Permalink to “多服支持”">​</a></h2><p>所有指令都支持多服前缀：</p><p><strong>日服（默认）</strong></p><div style="background:#f5f7fa;border-radius:12px;padding:16px;margin:12px 0;border-left:4px solid #4a90e2;"><div style="display:flex;align-items:center;margin-bottom:8px;"><span style="background:#4a90e2;color:white;padding:4px 12px;border-radius:12px;font-size:12px;font-weight:bold;">指令</span></div><div style="background:white;padding:12px 16px;border-radius:8px;font-family:monospace;color:#333;"> rk / b39 </div></div><p><strong>台服</strong></p><div style="background:#f5f7fa;border-radius:12px;padding:16px;margin:12px 0;border-left:4px solid #4a90e2;"><div style="display:flex;align-items:center;margin-bottom:8px;"><span style="background:#4a90e2;color:white;padding:4px 12px;border-radius:12px;font-size:12px;font-weight:bold;">指令</span></div><div style="background:white;padding:12px 16px;border-radius:8px;font-family:monospace;color:#333;"> twrk / twb39 </div></div><p><strong>国服</strong></p><div style="background:#f5f7fa;border-radius:12px;padding:16px;margin:12px 0;border-left:4px solid #4a90e2;"><div style="display:flex;align-items:center;margin-bottom:8px;"><span style="background:#4a90e2;color:white;padding:4px 12px;border-radius:12px;font-size:12px;font-weight:bold;">指令</span></div><div style="background:white;padding:12px 16px;border-radius:8px;font-family:monospace;color:#333;"> cnrk / cnb39 </div></div>',40)])])}const g=e(o,[["render",p]]);export{c as __pageData,g as default};
